"""시각화 및 피드백 API 엔드포인트."""

import logging

from fastapi import APIRouter, Depends, HTTPException, Request

from app.core.limiter import limiter
from app.services.code_executor import get_executor

logger = logging.getLogger("narrative_api.visualization")

# 시각화 도구 임포트
import sys as _sys
from pathlib import Path as _Path
_CHATBOT_PATH = str(_Path(__file__).resolve().parent.parent.parent.parent.parent / "chatbot")
if _CHATBOT_PATH not in _sys.path:
    _sys.path.insert(0, _CHATBOT_PATH)
try:
    from chatbot.tools.visualization_tool import _generate_with_claude, _generate_with_openai
    _VIZ_AVAILABLE = True
except ImportError:
    try:
        from tools.visualization_tool import _generate_with_claude, _generate_with_openai
        _VIZ_AVAILABLE = True
    except ImportError:
        _VIZ_AVAILABLE = False

router = APIRouter(prefix="/tutor", tags=["visualization"])


@router.post("/visualize")
@limiter.limit("5/minute")
async def generate_chart(request: Request):
    """시각화 생성 엔드포인트 (rate limit: 5/분)."""
    if not _VIZ_AVAILABLE:
        raise HTTPException(status_code=500, detail="시각화 모듈을 불러올 수 없습니다.")

    body = await request.json()
    description = body.get("description", "")
    data_context = body.get("data_context", "")
    if not description:
        raise HTTPException(status_code=400, detail="description이 필요합니다.")
    if len(description) > 500:
        raise HTTPException(status_code=400, detail="시각화 설명은 500자 이내로 입력해주세요.")
    if len(data_context) > 5000:
        data_context = data_context[:5000]

    code = _generate_with_claude(description, data_context)
    if not code:
        code = _generate_with_openai(description, data_context)
    if not code:
        return {"success": False, "error": "코드 생성 실패"}

    executor = get_executor()
    result = await executor.execute(code)
    return {
        "success": result.success,
        "html": result.output_html,
        "error": result.error,
        "execution_time_ms": result.execution_time_ms,
    }


@router.post("/feedback")
async def submit_feedback(request: Request) -> dict:
    """LangSmith 피드백 전송."""
    body = await request.json()
    run_id = body.get("run_id")
    score = body.get("score", 0)

    if not run_id:
        raise HTTPException(status_code=400, detail="run_id가 필요합니다.")

    try:
        from langsmith import Client as LangSmithClient
        ls_client = LangSmithClient()
        ls_client.create_feedback(run_id=run_id, key="user-score", score=score)
        return {"success": True}
    except ImportError:
        logger.warning("langsmith 패키지가 설치되지 않았습니다.")
        return {"success": False, "reason": "langsmith not installed"}
    except Exception as e:
        logger.warning("LangSmith 피드백 전송 실패: %s", e)
        return {"success": False, "reason": str(e)}

"""종목 감지 및 실시간 주가 조회 서비스.

KRX 전체 종목 목록을 캐시하여 메시지에서 종목명/코드를 동적으로 감지하고,
pykrx를 통해 실시간 주가 데이터를 조회한다.
"""

import logging
import re
import threading
from typing import Optional

logger = logging.getLogger("narrative_api.stock_resolver")

# --- 외부 모듈 임포트 (선택적) ---
import sys as _sys
from pathlib import Path as _Path

_PROJECT_ROOT = _Path(__file__).resolve().parent.parent.parent.parent
_PIPELINE_PATH = str(_PROJECT_ROOT / "datapipeline")
if _PIPELINE_PATH not in _sys.path:
    _sys.path.insert(0, _PIPELINE_PATH)

try:
    from collectors.stock_collector import get_stock_history
    _PYKRX_AVAILABLE = True
except ImportError:
    _PYKRX_AVAILABLE = False

try:
    from collectors.financial_collector import format_fundamentals_for_llm
    _FDR_AVAILABLE = True
except ImportError:
    _FDR_AVAILABLE = False

# --- KRX 종목 캐시 ---
_krx_cache: dict[str, str] = {}  # 종목명 → 코드
_krx_cache_lock = threading.Lock()
_krx_loaded = False


def _load_krx_listing():
    """pykrx로 KRX 전체 종목 목록을 로드하여 캐시 (최초 1회, 이후 재사용)."""
    global _krx_loaded
    if _krx_loaded:
        return
    with _krx_cache_lock:
        if _krx_loaded:
            return
        try:
            from pykrx import stock as pykrx_stock
            from datetime import datetime
            today = datetime.now().strftime("%Y%m%d")
            for market in ["KOSPI", "KOSDAQ"]:
                tickers = pykrx_stock.get_market_ticker_list(today, market=market)
                for ticker in tickers:
                    try:
                        name = pykrx_stock.get_market_ticker_name(ticker)
                        if name:
                            _krx_cache[name] = ticker
                    except Exception:
                        pass
            _krx_loaded = True
            logger.info("KRX 종목 목록 로드 완료: %d종목", len(_krx_cache))
        except Exception as e:
            logger.warning("KRX 종목 목록 로드 실패: %s (fallback 사용)", e)
            for name, code in {
                "삼성전자": "005930", "SK하이닉스": "000660", "LG에너지솔루션": "373220",
                "현대차": "005380", "NAVER": "035420", "카카오": "035720",
            }.items():
                _krx_cache[name] = code
            _krx_loaded = True


def detect_stock_codes(message: str) -> list[tuple[str, str]]:
    """메시지에서 종목명/코드를 동적으로 감지하여 (이름, 코드) 리스트 반환."""
    _load_krx_listing()
    found = []
    seen_codes = set()

    # 1) 6자리 숫자 종목 코드 직접 감지
    for code in re.findall(r'\b(\d{6})\b', message):
        if code not in seen_codes:
            found.append((code, code))
            seen_codes.add(code)

    # 2) KRX 종목명 매칭 (긴 이름부터)
    for name in sorted(_krx_cache.keys(), key=len, reverse=True):
        if len(name) >= 2 and name in message:
            code = _krx_cache[name]
            if code not in seen_codes:
                found.append((name, code))
                seen_codes.add(code)
            if len(found) >= 3:
                break

    return found[:3]


def should_auto_visualize(message: str, stock_detected: bool, prev_messages: list[dict] = None) -> bool:
    """메시지 맥락을 기반으로 시각화를 자동 생성해야 하는지 판단."""
    msg = message.lower()

    # 1) 명시적 시각화 키워드
    viz_signals = ["시각화", "차트", "그래프", "보여줘", "그려줘", "시각적", "그림으로", "표로",
                   "비교", "추세", "흐름", "변화"]
    if any(s in msg for s in viz_signals):
        return True

    # 2) 종목 감지 시 — 종목을 언급한 것 자체가 데이터 관심 신호
    if stock_detected:
        return True

    # 3) 이전 대화에서 종목이 언급된 경우 + 시각화 키워드
    if prev_messages:
        recent_text = " ".join(m.get("content", "") for m in prev_messages[-4:])
        has_prior_stock = any(name in recent_text for name in list(_krx_cache.keys())[:100])
        if has_prior_stock and any(s in msg for s in viz_signals):
            return True

    return False


def fetch_stock_data_for_context(stock_codes: list[tuple[str, str]]) -> tuple[str, dict]:
    """pykrx로 종목 주가를 조회하여 (컨텍스트 텍스트, 차트용 데이터) 반환."""
    if not _PYKRX_AVAILABLE or not stock_codes:
        return "", {}

    context_lines = []
    chart_data = {}

    for name, code in stock_codes:
        try:
            hist = get_stock_history(code, days=10)
            if not hist or not hist.get("history"):
                continue
            stock_name = hist.get("name", name)
            records = hist["history"]
            latest = records[-1] if records else {}

            context_lines.append(
                f"\n[{stock_name}({code}) 최근 주가]\n"
                f"  최근 종가: {latest.get('close', 0):,.0f}원\n"
                f"  등락률: {latest.get('change_pct', 0):+.2f}%\n"
                + "\n".join(
                    f"  {r['date']}: {r['close']:,.0f}원 ({r.get('change_pct', 0):+.2f}%)"
                    for r in records[-5:]
                )
            )
            chart_data[code] = {"name": stock_name, "history": records}
        except Exception as e:
            logger.debug("주가 조회 실패 (%s): %s", code, e)

    return "\n".join(context_lines), chart_data


def get_fundamentals_text(code: str) -> Optional[str]:
    """FinanceDataReader로 재무 지표 텍스트 반환. 실패 시 None."""
    if not _FDR_AVAILABLE:
        return None
    try:
        text = format_fundamentals_for_llm(code)
        if text and "찾을 수 없습니다" not in text:
            return text
    except Exception as e:
        logger.debug("FDR 재무 지표 실패 (%s): %s", code, e)
    return None

